try {
  const { task, data } = JSON.parse(query);

  if (task === 'break_even') {
    const fixedMonthly = (Number(data.monthly_insurance) || 0)
      + (Number(data.monthly_parking) || 0)
      + (Number(data.monthly_loan) || 0);
    const targetDays = Number(data.target_days) || 15;
    const cleanCost = Number(data.clean_cost) || 35;
    const avgTripDays = 2;
    const variablePerDay = cleanCost / avgTripDays;
    const depreciationPerDay = 0.33 * 40;
    const platformPct = (Number(data.platform_fee_pct) || 25) / 100;
    const protectionPct = (Number(data.protection_plan_pct) || 80) / 100;
    const hostReceivePct = protectionPct * (1 - platformPct);
    const mvr = ((fixedMonthly / targetDays) + variablePerDay + depreciationPerDay) / hostReceivePct;
    const breakEvenDays = Math.ceil(fixedMonthly / (mvr * hostReceivePct - variablePerDay - depreciationPerDay));
    return JSON.stringify({
      minimum_viable_rate: Math.ceil(mvr),
      fixed_monthly_cost: fixedMonthly.toFixed(2),
      variable_cost_per_day: variablePerDay.toFixed(2),
      depreciation_per_day: depreciationPerDay.toFixed(2),
      host_receive_pct: (hostReceivePct * 100).toFixed(1) + '%',
      break_even_days: breakEvenDays
    });
  }

  if (task === 'monthly_pnl') {
    const trips = data.trips || [];
    const expenses = data.expenses || [];
    const vehicle = data.vehicle || {};
    const grossRevenue = trips.reduce((s, t) => s + (Number(t.gross_revenue) || 0), 0);
    const platformFees = trips.reduce((s, t) => s + (Number(t.platform_fees) || 0), 0);
    const netRevenue = grossRevenue - platformFees;
    const expenseByCategory = {};
    let totalExpenses = 0;
    expenses.forEach(e => {
      const cat = e.category || 'other';
      const amt = Number(e.amount) || 0;
      expenseByCategory[cat] = (expenseByCategory[cat] || 0) + amt;
      totalExpenses += amt;
    });
    const totalMiles = trips.reduce((s, t) => s + (Number(t.miles_driven) || 0), 0);
    const depreciation = totalMiles * 0.33;
    const fixedMonthly = (Number(vehicle.monthly_insurance) || 0)
      + (Number(vehicle.monthly_parking) || 0)
      + (Number(vehicle.monthly_loan) || 0);
    const totalCosts = totalExpenses + depreciation + fixedMonthly;
    const netProfit = netRevenue - totalCosts;
    const totalDays = trips.reduce((s, t) => s + (Number(t.days) || 0), 0);
    const margin = grossRevenue > 0 ? ((netProfit / grossRevenue) * 100).toFixed(1) : '0.0';
    return JSON.stringify({
      gross_revenue: grossRevenue.toFixed(2),
      platform_fees: platformFees.toFixed(2),
      net_revenue: netRevenue.toFixed(2),
      expense_breakdown: expenseByCategory,
      total_variable_expenses: totalExpenses.toFixed(2),
      depreciation: depreciation.toFixed(2),
      fixed_costs: fixedMonthly.toFixed(2),
      total_costs: totalCosts.toFixed(2),
      net_profit: netProfit.toFixed(2),
      profit_margin_pct: margin,
      days_booked: totalDays,
      utilization_pct: ((totalDays / 30) * 100).toFixed(1),
      total_miles: totalMiles,
      biggest_cost: Object.entries(expenseByCategory).sort((a, b) => b[1] - a[1])[0] || ['none', 0]
    });
  }

  if (task === 'pricing_recommendation') {
    const mvr = Number(data.mvr) || 0;
    const marketAvg = Number(data.market_avg) || 0;
    const currentRate = Number(data.current_rate) || 0;
    const utilization = Number(data.utilization) || 50;
    let weekdayRate = Math.max(mvr, marketAvg * 0.9);
    let weekendRate = weekdayRate * 1.2;
    if (utilization > 80) { weekdayRate *= 1.1; weekendRate *= 1.15; }
    if (utilization < 40) { weekdayRate *= 0.95; }
    weekdayRate = Math.max(weekdayRate, mvr);
    weekendRate = Math.max(weekendRate, mvr);
    return JSON.stringify({
      recommended_weekday: Math.ceil(weekdayRate),
      recommended_weekend: Math.ceil(weekendRate),
      minimum_floor: Math.ceil(mvr),
      market_average: marketAvg.toFixed(2),
      current_rate: currentRate.toFixed(2),
      position_vs_market: currentRate > 0 && marketAvg > 0
        ? ((currentRate / marketAvg) * 100).toFixed(0) + '% of market avg'
        : 'no market data'
    });
  }

  if (task === 'roi') {
    const price = Number(data.purchase_price) || 1;
    const profit = Number(data.annual_net_profit) || 0;
    const roi = (profit / price) * 100;
    const paybackMonths = profit > 0 ? Math.ceil((price / profit) * 12) : Infinity;
    return JSON.stringify({
      annual_roi_pct: roi.toFixed(1),
      payback_months: paybackMonths,
      monthly_avg_profit: (profit / 12).toFixed(2)
    });
  }

  if (task === 'depreciation') {
    const miles = Number(data.miles_this_period) || 0;
    const irsCost = miles * 0.33;
    const irsTotal = miles * 0.70;
    return JSON.stringify({
      depreciation_cost: irsCost.toFixed(2),
      irs_total_deduction: irsTotal.toFixed(2),
      miles: miles,
      rate_per_mile: '$0.33 (IRS depreciation component)'
    });
  }

  return JSON.stringify({ error: 'Unknown task', task });
} catch (e) {
  return 'Error: ' + e.message + '. Send JSON: {"task": "break_even", "data": {...}}';
}

const errorMessage = $json.execution?.error?.message || 'Unknown error';
const workflowName = $json.workflow?.name || 'FLEET';
const timestamp = new Date().toISOString();

return [{
  json: {
    error: errorMessage,
    workflow: workflowName,
    timestamp: timestamp,
    summary: `FLEET Error at ${timestamp}: ${errorMessage}`
  }
}];
